:root {
  --brand: #4f46e5;
  --space: 1rem;
}
.button {
  background: var(--brand);
  padding: var(--space);
  /* fallback if undefined */
  color: var(--btn-text, #fff);
}

.link:hover { color: teal; }
.badge::after {
  content: "\2713";
  margin-left: .25rem;
}

.modal { position: fixed; z-index: 1000; }
/* creates a stacking context, trapping children */
.card { transform: translateZ(0); }
.card .tooltip { z-index: 9999; /* still stuck inside .card */ }

.btn { transition: background .2s ease; }
.btn:hover { background: navy; }
@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: .4; }
}
.loader { animation: pulse 1s infinite; }

.card:hover {
  transform: translateY(-4px) scale(1.02);
}
.icon {
  transform-origin: center;
  transform: rotate(45deg);
}

html { font-size: 16px; }
.title { font-size: 2rem; }      /* 32px */
.card { padding: 1.5em; }        /* relative to card font-size */

.hero-title {
  font-size: clamp(1.5rem, 4vw + 1rem, 3rem);
}
.container {
  width: min(90%, 1100px);
}

.parent { color: navy; }
.child { color: inherit; }
.reset { all: unset; }

.sidebar {
  container-type: inline-size;
  container-name: panel;
}
@container panel (min-width: 400px) {
  .card { display: grid; grid-template-columns: 1fr 2fr; }
}

.section-header {
  position: sticky;
  top: 0;
}
/* This ancestor would break sticky: */
.wrapper { overflow: hidden; }

@layer reset, base, components, utilities;
@layer base {
  a { color: blue; }
}
@layer utilities {
  .text-red { color: red; } /* wins over base */
}

.page {
  display: grid;
  grid-template-areas:
    "header header"
    "nav    main"
    "footer footer";
  gap: 1rem;
}
.header { grid-area: header; }
.main { grid-area: main; }

.card {
  padding-block: 1rem;
  padding-inline: 1.5rem;
  margin-inline-start: auto;
}

.panel {
  will-change: transform;
}
/* better: toggle it only when needed via a class */
.panel.is-animating { will-change: transform, opacity; }

:root {
  color-scheme: light dark;
  --bg: #ffffff;
  --text: #111111;
}
@media (prefers-color-scheme: dark) {
  :root {
    --bg: #0f172a;
    --text: #e2e8f0;
  }
}
body { background: var(--bg); color: var(--text); }
